// Description: Discovers Portworx storage nodes from px_cluster_status_nodes_online via Thanos Querier.
// Description: Extracts node identity from px_node_status metric labels.
import groovy.json.JsonSlurper
import javax.net.ssl.*
import java.security.cert.X509Certificate

def host = hostProps.get("openshift.thanos.host")
def token = hostProps.get("openshift.thanos.pass")
def port = hostProps.get("openshift.thanos.port") ?: "443"
def useSsl = (hostProps.get("openshift.thanos.ssl") ?: "true").toLowerCase() == "true"

if (!host || !token) {
    println "openshift.thanos.host and openshift.thanos.pass properties are required"
    return 1
}

def trustAllCerts = [
    checkClientTrusted: { chain, authType -> },
    checkServerTrusted: { chain, authType -> },
    getAcceptedIssuers: { null }
] as X509TrustManager

def sc = SSLContext.getInstance("TLS")
sc.init(null, [trustAllCerts] as TrustManager[], null)
HttpsURLConnection.setDefaultSSLSocketFactory(sc.getSocketFactory())
HttpsURLConnection.setDefaultHostnameVerifier({ hostname, session -> true } as HostnameVerifier)

def proto = useSsl ? "https" : "http"
def baseUrl = "${proto}://${host}:${port}"

try {
    def query = 'px_node_status_node_status'
    def encoded = java.net.URLEncoder.encode(query, "UTF-8")
    def url = new URL("${baseUrl}/api/v1/query?query=${encoded}")
    def conn = url.openConnection()
    conn.setRequestProperty("Authorization", "Bearer ${token}")
    conn.setConnectTimeout(30000)
    conn.setReadTimeout(30000)

    if (conn.responseCode == 200) {
        def response = conn.inputStream.text
        def json = new JsonSlurper().parseText(response)

        if (json.status == "success" && json.data?.result) {
            def seen = [] as Set
            json.data.result.each { result ->
                def labels = result.metric
                def nodeId = labels.node_id ?: labels.node ?: labels.instance ?: "unknown"
                def nodeName = labels.node_name ?: labels.hostname ?: nodeId

                if (!seen.contains(nodeId)) {
                    seen.add(nodeId)
                    def displayName = nodeName
                    def description = "Portworx node ${nodeName}"

                    println "${nodeId}##${displayName}##${description}####auto.node.id=${nodeId}&auto.node.name=${nodeName}"
                }
            }
        }
    } else {
        System.err.println("Discovery failed: HTTP ${conn.responseCode}")
    }
} catch (Exception e) {
    System.err.println("Discovery error: ${e.message}")
    return 1
}
return 0

